cache = {}
database = {1: "Alice", 2: "Bob", 3: "Charlie"}

def get_user(user_id):
    # 1. Check cache first
    if user_id in cache:
        print("Cache HIT!")
        return cache[user_id]

    print("Cache MISS! Fetching from DB...")
    # 2. Fetch from DB
    user_data = database.get(user_id)

    # 3. Save to cache for next time
    if user_data:
        cache[user_id] = user_data

    return user_data

