def get_distance(x1, y1, x2, y2):
    # Manhattan distance: |x1 - x2| + |y1 - y2|
    return abs(x1 - x2) + abs(y1 - y2)

rider = (10, 10)
drivers = {
    'DriverX': (15, 12),
    'DriverY': (8, 9),
    'DriverZ': (20, 20)
}

